import"./hoisted.CbBF7shr.js";document.querySelectorAll(".copy-link").forEach(t=>{t.addEventListener("click",async()=>{const e=t.getAttribute("data-copy")||"";try{await navigator.clipboard.writeText(e);const o=t.textContent;t.textContent="Copied!",t.classList.add("copied"),setTimeout(()=>{t.textContent=o,t.classList.remove("copied")},1800)}catch{window.prompt("Copy this link:",e)}})});
